  const fMargenUnitario = "$$ Margen\\ Unitario\\ (\\%) = \\left( \\frac{Beneficio\\ por\\ Unidad}{Precio\\ de\\ Venta} \\right) \\times 100 $$";
  return renderTemplate`${renderComponent($$result, "Layout", $$Layout, { "title": "Calculadora de Beneficio por Unidad | Optimiza tu Margen de Producto", "description": "Calcula cuánto ganas por cada producto vendido. Guía completa de 1000 palabras sobre costes unitarios, márgenes y rentabilidad de inventario." }, { "default": ($$result2) => renderTemplate(_a || (_a = __template([" ", '<main class="max-w-5xl mx-auto px-4 py-12"> <header class="text-center mb-16"> <h1 class="text-4xl md:text-6xl font-black text-slate-900 mb-4 tracking-tight">\nCalculadora de <span class="text-indigo-600">Beneficio por Unidad</span> 📦\n</h1> <p class="text-slate-500 text-lg font-medium max-w-2xl mx-auto text-balance">\nDescubre la rentabilidad real de tus productos tras descontar los costes\n        directos de fabricación y venta.\n</p> </header> <section class="bg-white p-6 md:p-12 rounded-[3rem] border border-slate-100 shadow-2xl max-w-4xl mx-auto mb-20"> <div class="grid md:grid-cols-2 gap-8 mb-8"> <div class="space-y-4"> <label for="precioVenta" class="block text-xs font-bold text-slate-400 uppercase tracking-widest ml-2">Precio de Venta ($)</label> <input type="number" id="precioVenta" step="0.01" placeholder="Ej: 50.00" class="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-indigo-500 outline-none transition-all shadow-inner font-bold"> </div> <div class="space-y-4"> <label for="costeUnitario" class="block text-xs font-bold text-slate-400 uppercase tracking-widest ml-2">Coste Variable Unitario ($)</label> <input type="number" id="costeUnitario" step="0.01" placeholder="Ej: 20.00" class="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-indigo-500 outline-none transition-all shadow-inner font-bold"> </div> </div> <button id="btnCalcularMargen" class="w-full bg-slate-900 text-white p-6 rounded-[2rem] font-bold hover:bg-indigo-600 transition-all shadow-lg active:scale-95 text-xl">\nCalcular Beneficio\n</button> <div id="resultadoPanel" class="hidden mt-10 space-y-4 animate-in fade-in slide-in-from-bottom-4 duration-500"> <div class="bg-indigo-50 p-10 rounded-[2.5rem] border border-indigo-100 text-center"> <span class="block text-xs font-bold text-indigo-400 uppercase mb-2 tracking-widest">Beneficio Neto por Unidad</span> <span id="valorBeneficio" class="block text-6xl font-black text-indigo-700">$0.00</span> </div> <div class="grid grid-cols-2 gap-4"> <div class="bg-slate-50 p-6 rounded-3xl text-center"> <span id="valorPorcentaje" class="block text-xl font-bold text-slate-800">0%</span> <span class="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Margen sobre Venta</span> </div> <div class="bg-slate-50 p-6 rounded-3xl text-center"> <span id="valorMarkup" class="block text-xl font-bold text-slate-800">0%</span> <span class="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Markup sobre Coste</span> </div> </div> </div> </section> <article class="prose prose-slate max-w-none border-t border-slate-200 pt-16 text-slate-700 font-light leading-relaxed"> <h2 class="text-3xl font-black text-slate-900 mb-6 italic">\nEntendiendo el Beneficio por Unidad: La Base de la Viabilidad Comercial\n</h2> <p class="mb-6">\nEn el mundo de los negocios, ya sea que gestiones un pequeño ecommerce o\n        una planta de fabricación industrial, el <strong>beneficio por unidad</strong> es la métrica fundamental que determina si tu modelo operativo es sostenible\n        a largo plazo. No importa cuánto factures mensualmente; si el beneficio que\n        queda tras vender cada unidad no es suficiente para cubrir tus costes fijos\n        y generar un excedente, tu empresa se encuentra en una situación de riesgo\n        financiero.\n</p> <p class="mb-6">\nEste indicador, también conocido como margen de contribución unitario,\n        nos revela la salud intrínseca de nuestro producto. Al aislar el\n        rendimiento de un solo ítem, podemos tomar decisiones críticas: ¿Debemos\n        discontinuar un producto? ¿Podemos permitirnos una campaña de descuentos\n        agresiva? ¿Es necesario negociar con los proveedores para bajar el coste\n        de adquisición? Todas estas respuestas nacen del cálculo que realizamos\n        hoy con esta herramienta.\n</p> <h3 class="text-2xl font-bold text-slate-800 mb-4">\n¿Por qué el Beneficio Unitario es distinto al Beneficio Neto Total?\n</h3> <p class="mb-6">\nEs vital entender la jerarquía de las finanzas. El beneficio por unidad\n        solo tiene en cuenta los <strong>costes variables</strong> (aquellos que aumentan\n        o disminuyen directamente con el volumen de producción). El beneficio neto\n        total de la empresa, por otro lado, debe restar además los costes fijos (alquiler,\n        salarios administrativos, software, luz). Por lo tanto, el beneficio por unidad\n        debe ser lo suficientemente alto como para que, multiplicado por el volumen\n        de ventas, supere todos los costes fijos del mes.\n</p> <h3 class="text-2xl font-bold text-slate-800 mb-4">\nLa Fórmula Matemática del Beneficio Unitario\n</h3> <p class="mb-6">\nLa expresión matemática para obtener el beneficio bruto por unidad es\n        lineal y directa, aunque su ejecución requiere una contabilidad de\n        costes precisa:\n</p> <div class="bg-slate-50 p-8 rounded-3xl mb-10 border border-slate-100 text-center font-serif text-xl"> ', ' </div> <h3 class="text-2xl font-bold text-slate-800 mb-4">\nAnálisis de las Variables\n</h3> <ul class="list-disc pl-6 mb-8 space-y-4"> <li> <strong>Precio de Venta:</strong> Es el importe final (sin IVA/Impuestos)\n          al que el cliente final adquiere el producto.\n</li> <li> <strong>Coste Variable Unitario:</strong> Aquí reside la complejidad. Debes\n          incluir el precio de compra al proveedor, el embalaje individual (packaging),\n          las comisiones de pasarelas de pago (Stripe/PayPal), los gastos de envío\n          si están incluidos y cualquier mano de obra directa necesaria para preparar\n          esa unidad específica.\n</li> </ul> <h3 class="text-2xl font-bold text-slate-800 mb-4">\nMargen vs. Markup: No cometas este error común\n</h3> <p class="mb-6">\nMuchos emprendedores confunden el margen de beneficio con el markup. El <strong>Margen</strong> se calcula sobre el precio de venta (¿Qué porcentaje del precio final es\n        beneficio?). El <strong>Markup</strong> se calcula sobre el coste (¿Cuánto\n        porcentaje le sumé al coste para llegar al precio?).\n</p> <div class="bg-slate-50 p-8 rounded-3xl mb-10 border border-slate-100 text-center font-serif text-xl"> ', ' </div> <h3 class="text-2xl font-bold text-slate-800 mb-4">\nCasos de Uso Reales: Del Retail al SaaS\n</h3> <p class="mb-6"> <strong>1. Ecommerce de Dropshipping:</strong> En este modelo, el beneficio\n        por unidad suele ser ajustado. Conocerlo al céntimo permite decidir si una\n        inversión en anuncios (Facebook/TikTok Ads) es rentable o si el coste de adquisición\n        de cliente (CAC) superará nuestro beneficio unitario.\n</p> <p class="mb-6"> <strong>2. Restauración y Gastronomía:</strong> Aquí se conoce como "escandallo".\n        Calcular el beneficio por unidad de un plato específico ayuda a los chefs\n        a equilibrar la carta, mezclando platos de "volumen" con platos de "alta rentabilidad".\n</p> <p class="mb-6"> <strong>3. Servicios Profesionales:</strong> Aunque parezca etéreo, una hora\n        de consultoría tiene un coste variable (tu tiempo valorado en base a tu capacidad).\n        El beneficio unitario por hora vendida es la métrica de éxito de cualquier\n        consultor independiente.\n</p> <h3 class="text-2xl font-bold text-slate-800 mb-4">\nCómo optimizar el Beneficio por Unidad\n</h3> <p class="mb-6">\nExisten tres palancas principales para mejorar este indicador:\n</p> <ul class="list-decimal pl-6 mb-8 space-y-4"> <li> <strong>Economías de escala:</strong> Comprar más volumen al proveedor para\n          reducir el coste unitario de adquisición.\n</li> <li> <strong>Optimización de Packaging:</strong> A veces, cambiar el diseño de\n          la caja puede ahorrar céntimos que, multiplicados por miles de ventas, suponen\n          miles de euros en beneficio.\n</li> <li> <strong>Valor Percibido:</strong> Mejorar el branding para justificar un\n          aumento del precio de venta sin necesidad de alterar el producto físico.\n</li> </ul> <h2 class="text-3xl font-black text-slate-900 mb-8 italic">\nSección de Ejemplos Prácticos Paso a Paso\n</h2> <div class="space-y-12 mb-20"> <div class="p-8 bg-indigo-50 rounded-[2.5rem] border border-indigo-100 shadow-sm" id="ejemplo1"> <h3 class="text-xl font-bold text-indigo-900 mb-4">\nEjemplo 1: Tienda de Accesorios Electrónicos\n</h3> <p class="mb-4">\nCalculamos el beneficio de vender un soporte de smartphone.\n</p> <div class="bg-white p-6 rounded-2xl mb-4"> <ul class="text-sm space-y-3"> <li> <strong>Valores:</strong> Precio Venta = $15.00 | Coste Adquisición\n                = $4.00 | Envío = $2.00 | Comisión Pago = $0.50\n</li> <li> <strong>Cálculo del Coste Total:</strong> $4.00 + $2.00 + $0.50 =\n                $6.50\n</li> <li> <strong>Cálculo del Beneficio:</strong> $15.00 - $6.50 = $8.50\n</li> <li> <strong>Resultado Final:</strong> El beneficio por unidad es de <strong>$8.50</strong>, con un margen del 56.6%.\n</li> </ul> </div> </div> <div class="p-8 bg-slate-50 rounded-[2.5rem] border border-slate-100 shadow-sm" id="ejemplo2"> <h3 class="text-xl font-bold text-slate-900 mb-4">\nEjemplo 2: Venta de Software (SaaS) - Costes de Servidor\n</h3> <p class="mb-4">\nAunque el software es digital, cada usuario nuevo genera un coste\n            variable mínimo.\n</p> <div class="bg-white p-6 rounded-2xl mb-4"> <ul class="text-sm space-y-3"> <li> <strong>Valores:</strong> Suscripción Mensual = $29.00 | Coste Servidor\n                por Usuario = $1.50 | Soporte Proporcional = $3.00\n</li> <li> <strong>Cálculo:</strong> $29.00 - ($1.50 + $3.00) = $24.50\n</li> <li> <strong>Resultado Final:</strong> El beneficio unitario por suscriptor\n                es de <strong>$24.50</strong>.\n</li> <li> <strong>Análisis:</strong> El margen es altísimo (84.4%), típico de\n                productos digitales escalables.\n</li> </ul> </div> </div> <div class="p-8 bg-emerald-50 rounded-[2.5rem] border border-emerald-100 shadow-sm" id="ejemplo3"> <h3 class="text-xl font-bold text-emerald-900 mb-4">\nEjemplo 3: Fabricación de Muebles Artesanales\n</h3> <p class="mb-4">Análisis de una silla de madera de diseño.</p> <div class="bg-white p-6 rounded-2xl mb-4"> <ul class="text-sm space-y-3"> <li> <strong>Valores:</strong> Precio Venta = $250.00 | Madera = $60.00\n                | Barniz/Herrajes = $15.00 | Mano Obra Directa = $80.00\n</li> <li> <strong>Cálculo:</strong> $250.00 - ($60.00 + $15.00 + $80.00) = $95.00\n</li> <li> <strong>Resultado Final:</strong> El beneficio neto por silla es de\n<strong>$95.00</strong>.\n</li> <li> <strong>Estrategia:</strong> El artesano sabe que debe vender al menos\n                20 sillas al mes para cubrir su alquiler de taller de $1800.\n</li> </ul> </div> </div> </div> <h2 class="text-2xl font-bold text-slate-800 mb-4">\nConclusión Educativa\n</h2> <p class="mb-6">\nDominar el beneficio por unidad es pasar de "jugar a los negocios" a\n        gestionar una empresa con datos científicos. Esta cifra es el motor que\n        alimenta el crecimiento. Si el beneficio unitario es saludable, el\n        negocio puede escalar; si es anémico o negativo, cada nueva venta es un\n        paso más hacia la quiebra. Revisa estos números trimestralmente, ya que\n        la inflación y los costes de logística suelen fluctuar de forma\n        silenciosa.\n</p> <footer class="bg-slate-900 text-white p-12 rounded-[3rem] text-center italic mt-12 shadow-2xl"> <p class="text-indigo-400 font-bold mb-2">Reflexión Final:</p> <p class="text-sm text-slate-400">\n"El volumen de ventas da ego, el beneficio neto da libertad. Empieza\n          calculando tu margen unidad por unidad."\n</p> </footer> </article> </main> <script>\n    (function () {\n      const btn = document.querySelector("#btnCalcularMargen");\n      const inPrecio = document.querySelector("#precioVenta");\n      const inCoste = document.querySelector("#costeUnitario");\n\n      const panel = document.querySelector("#resultadoPanel");\n      const outBen = document.querySelector("#valorBeneficio");\n      const outPct = document.querySelector("#valorPorcentaje");\n      const outMark = document.querySelector("#valorMarkup");\n\n      btn.addEventListener("click", function () {\n        const precio = parseFloat(inPrecio.value) || 0;\n        const coste = parseFloat(inCoste.value) || 0;\n\n        if (precio <= 0) {\n          alert("Por favor, introduce un precio de venta válido.");\n          return;\n        }\n\n        const beneficio = precio - coste;\n        const margen = (beneficio / precio) * 100;\n        const markup = coste > 0 ? (beneficio / coste) * 100 : 0;\n\n        // Renderizado de resultados\n        outBen.textContent = "$" + beneficio.toFixed(2);\n        outPct.textContent = margen.toFixed(1) + "%";\n        outMark.textContent = markup.toFixed(1) + "%";\n\n        panel.classList.remove("hidden");\n      });\n    })();\n  <\/script> '])), maybeRenderHead(), fBeneficioBruto, fMargenUnitario) })}`;
